+        // Alpine.js global store - bridges Nanostores to Alpine reactivity
+        document.addEventListener('alpine:init', () => {
+            Alpine.store('app', {
+                bytesDownloaded: 0,
+                requests: 0,
+                formatBytes(bytes) {
+                    if (bytes === 0) return '0 B';
+                    const k = 1024;
+                    const sizes = ['B', 'KB', 'MB', 'GB'];
+                    const i = Math.floor(Math.log(bytes) / Math.log(k));
+                    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
+                }
+            });
+
+            // Sync Nanostores → Alpine store
+            $totalBytesDownloaded.subscribe(v => Alpine.store('app').bytesDownloaded = v);
+            $totalRequests.subscribe(v => Alpine.store('app').requests = v);
+        });
+
+        // Start Alpine
+        Alpine.start();
